import os from "node:os";
import { Worker } from "node:worker_threads";
import { existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { cosineSimilarity } from "@langchain/core/utils/math";

/** Minimum row count below which synchronous is faster than worker overhead. */
const MIN_PARALLEL_ROWS = 50;

type DType = "float32" | "float64";

export type FlatCosineMatrix = {
  data: Float32Array | Float64Array;
  rows: number;
  cols: number;
};

function resolveWorkerUrl(): URL {
  const runningTsSource = new URL(import.meta.url).pathname.endsWith('.ts');
  const workerCandidates = runningTsSource
    ? ['./cosineSimilarityWorker.ts', './services/cosineSimilarityWorker.ts']
    : ['./cosineSimilarityWorker.js', './services/cosineSimilarityWorker.js'];

  const workerUrl = workerCandidates
    .map((candidate) => new URL(candidate, import.meta.url))
    .find((url) => existsSync(fileURLToPath(url)));

  if (!workerUrl) {
    throw new Error(
      `cosineSimilarityWorker not found next to ${fileURLToPath(new URL(import.meta.url))}. Tried: ${workerCandidates.join(", ")}`
    );
  }
  return workerUrl;
}

function execArgvForWorker(): string[] {
  const runningTsSource = new URL(import.meta.url).pathname.endsWith('.ts');
  return runningTsSource ? ['--import', 'tsx/esm'] : [];
}

function packToBuffer(rows: number[][], dims: number, dtype: DType): ArrayBuffer {
  if (dtype === "float64") {
    const flat = new Float64Array(rows.length * dims);
    rows.forEach((row, i) => flat.set(row, i * dims));
    return flat.buffer;
  }
  const flat = new Float32Array(rows.length * dims);
  rows.forEach((row, i) => {
    for (let j = 0; j < dims; j++) flat[i * dims + j] = row[j] ?? 0;
  });
  return flat.buffer;
}

function makeNormsBuffer(allBuffer: SharedArrayBuffer, rowCount: number, dims: number, dtype: DType): SharedArrayBuffer {
  const bytes = dtype === "float64" ? 8 : 4;
  const norms = new SharedArrayBuffer(rowCount * bytes);
  if (dtype === "float64") {
    const b = new Float64Array(allBuffer);
    const out = new Float64Array(norms);
    for (let i = 0; i < rowCount; i++) {
      let sum = 0;
      const base = i * dims;
      for (let k = 0; k < dims; k++) {
        const v = b[base + k] ?? 0;
        sum += v * v;
      }
      out[i] = Math.sqrt(sum);
    }
    return norms;
  }

  const b = new Float32Array(allBuffer);
  const out = new Float32Array(norms);
  for (let i = 0; i < rowCount; i++) {
    let sum = 0;
    const base = i * dims;
    for (let k = 0; k < dims; k++) {
      const v = b[base + k] ?? 0;
      sum += v * v;
    }
    out[i] = Math.sqrt(sum);
  }
  return norms;
}

/**
 * Computes cosineSimilarity(A, B) into a flat typed-array (row-major) using workers.
 * This avoids allocating a massive number[][] which will OOM for large matrices.
 */
export async function parallelCosineSimilarityFlat(
  A: number[][],
  B: number[][],
  dtype: DType = "float32",
): Promise<FlatCosineMatrix> {
  if (A.length === 0 || B.length === 0) {
    const empty = dtype === "float64" ? new Float64Array(0) : new Float32Array(0);
    return { data: empty, rows: A.length, cols: B.length };
  }

  const dims = A[0].length;
  const chunkSize = Math.ceil(A.length / os.cpus().length);
  const bytes = dtype === "float64" ? 8 : 4;

  // Input B in shared memory.
  const sharedB = new SharedArrayBuffer(B.length * dims * bytes);
  if (dtype === "float64") {
    const bView = new Float64Array(sharedB);
    B.forEach((row, i) => bView.set(row, i * dims));
  } else {
    const bView = new Float32Array(sharedB);
    B.forEach((row, i) => {
      for (let j = 0; j < dims; j++) bView[i * dims + j] = row[j] ?? 0;
    });
  }

  const normsB = makeNormsBuffer(sharedB, B.length, dims, dtype);
  const sharedResult = new SharedArrayBuffer(A.length * B.length * bytes);

  // For small matrices, synchronous is fine (and avoids worker overhead).
  if (A.length < MIN_PARALLEL_ROWS) {
    const m = cosineSimilarity(A, B);
    const out = dtype === "float64" ? new Float64Array(A.length * B.length) : new Float32Array(A.length * B.length);
    for (let i = 0; i < A.length; i++) {
      for (let j = 0; j < B.length; j++) out[i * B.length + j] = m[i]?.[j] ?? 0;
    }
    return { data: out, rows: A.length, cols: B.length };
  }

  const workerUrl = resolveWorkerUrl();
  const execArgv = execArgvForWorker();

  let rowOffset = 0;
  const chunks = Array.from({ length: Math.ceil(A.length / chunkSize) }, (_, i) => {
    const chunk = A.slice(i * chunkSize, (i + 1) * chunkSize);
    const startRow = rowOffset;
    rowOffset += chunk.length;
    return { chunk, startRow };
  });

  await Promise.all(
    chunks.map(({ chunk, startRow }) =>
      runWorkerFlat(chunk, sharedB, normsB, B.length, dims, sharedResult, startRow, dtype, workerUrl, execArgv)
    )
  );

  const data = dtype === "float64" ? new Float64Array(sharedResult) : new Float32Array(sharedResult);
  return { data, rows: A.length, cols: B.length };
}

/**
 * Computes cosineSimilarity(A, B) using worker threads for large inputs,
 * falling back to the synchronous library call for small ones.
 * B and the result matrix are both in SharedArrayBuffer — no serialization needed.
 */
export async function parallelCosineSimilarity(A: number[][], B: number[][]): Promise<number[][]> {
  if (A.length === 0 || B.length === 0) return [];
  if (A.length < MIN_PARALLEL_ROWS) return cosineSimilarity(A, B);

  // Guardrail: callers should use the flat API for large matrices to avoid OOM.
  // (This function returns number[][] which is not viable at big sizes.)
  const cells = A.length * B.length;
  if (cells > 5_000_000) {
    throw new Error(
      `parallelCosineSimilarity would allocate a huge number[][] (${A.length}×${B.length}). ` +
        `Use parallelCosineSimilarityFlat(...) instead.`
    );
  }

  const dims = A[0].length;
  const chunkSize = Math.ceil(A.length / os.cpus().length);

  const sharedB = new SharedArrayBuffer(B.length * dims * 8);
  const bView = new Float64Array(sharedB);
  B.forEach((row, i) => bView.set(row, i * dims));

  // Allocate SharedArrayBuffer for output matrix (A.length × B.length).
  // Workers write directly to this instead of serializing results.
  const sharedResult = new SharedArrayBuffer(A.length * B.length * 8);

  const runningTsSource = new URL(import.meta.url).pathname.endsWith('.ts');

  const workerCandidates = runningTsSource
    ? ['./cosineSimilarityWorker.ts', './services/cosineSimilarityWorker.ts']
    : ['./cosineSimilarityWorker.js', './services/cosineSimilarityWorker.js'];

  const workerUrl = workerCandidates
    .map((candidate) => new URL(candidate, import.meta.url))
    .find((url) => existsSync(fileURLToPath(url)));

  if (!workerUrl) {
    throw new Error(
      `cosineSimilarityWorker not found next to ${fileURLToPath(new URL(import.meta.url))}. Tried: ${workerCandidates.join(", ")}`
    );
  }

  const execArgv = runningTsSource ? ['--import', 'tsx/esm'] : [];

  // Create chunks with their row offsets in the output matrix
  let rowOffset = 0;
  const chunks = Array.from(
    { length: Math.ceil(A.length / chunkSize) },
    (_, i) => {
      const chunk = A.slice(i * chunkSize, (i + 1) * chunkSize);
      const startRow = rowOffset;
      rowOffset += chunk.length;
      return { chunk, startRow };
    }
  );

  await Promise.all(
    chunks.map(({ chunk, startRow }) =>
      runWorker(chunk, sharedB, B.length, dims, sharedResult, startRow, workerUrl, execArgv)
    )
  );

  // Convert SharedArrayBuffer back to regular array of arrays
  const resultView = new Float64Array(sharedResult);
  const result: number[][] = [];
  for (let i = 0; i < A.length; i++) {
    const row: number[] = [];
    for (let j = 0; j < B.length; j++) {
      row.push(resultView[i * B.length + j]);
    }
    result.push(row);
  }
  return result;
}

function runWorker(
  chunk: number[][],
  sharedB: SharedArrayBuffer,
  bCount: number,
  dims: number,
  sharedResult: SharedArrayBuffer,
  startRow: number,
  workerUrl: URL,
  execArgv: string[],
): Promise<void> {
  return new Promise((resolve, reject) => {
    const rowsFlat = new Float64Array(chunk.length * dims);
    chunk.forEach((row, i) => rowsFlat.set(row, i * dims));

    const worker = new Worker(workerUrl, {
      workerData: {
        rowsBuffer: rowsFlat.buffer,
        rowCount: chunk.length,
        allBuffer: sharedB,
        allCount: bCount,
        dims,
        resultBuffer: sharedResult,
        startRow,
      },
      transferList: [rowsFlat.buffer],
      execArgv,
    });

    worker.once("message", () => resolve());
    worker.once("error", reject);
  });
}

function runWorkerFlat(
  chunk: number[][],
  sharedB: SharedArrayBuffer,
  normsB: SharedArrayBuffer,
  bCount: number,
  dims: number,
  sharedResult: SharedArrayBuffer,
  startRow: number,
  dtype: DType,
  workerUrl: URL,
  execArgv: string[],
): Promise<void> {
  return new Promise((resolve, reject) => {
    const rowsBuffer = packToBuffer(chunk, dims, dtype);
    const worker = new Worker(workerUrl, {
      workerData: {
        mode: "flat",
        dtype,
        rowsBuffer,
        rowCount: chunk.length,
        allBuffer: sharedB,
        allCount: bCount,
        normsBuffer: normsB,
        dims,
        resultBuffer: sharedResult,
        startRow,
      },
      transferList: [rowsBuffer],
      execArgv,
    });

    worker.once("message", () => resolve());
    worker.once("error", reject);
  });
}

// Mutable export for test stubbing and for callers that want an indirection layer.
export const similarityApi = {
  parallelCosineSimilarity,
  parallelCosineSimilarityFlat,
};
